UPDATE users SET last_login = NOW() - INTERVAL '1 hour'   WHERE email = 'analyst1@ongc.com';
UPDATE users SET last_login = NOW() - INTERVAL '3 hours'  WHERE email = 'analyst2@ongc.com';
UPDATE users SET last_login = NOW() - INTERVAL '5 hours'  WHERE email = 'apiconsumer1@ongc.com';
UPDATE users SET last_login = NOW() - INTERVAL '1 day'    WHERE email = 'apiconsumer2@ongc.com';

-- ── 2. UPDATE token total_requests ────────────────────
